<template>
	<div class="container">
		<div class="title">hkanye的博客</div>
		<div class="home">
			<!-- <img alt="Vue logo" src="../assets/logo.png">
			<HelloWorld msg="Welcome to Your Vue.js App"/> -->
			<div style="width: 100%">
				<div class="aCard" v-for="(item) in articalData" :key="item.number" @click="openArtical(item.number)">
					<div class="cardTitle">{{item.title}}</div>
					<!-- <div class="cardIntro">{{item.url}}</div> -->
					<div class="cardTime">{{item.updated_at}}</div>
				</div>
			</div>
			<!-- <div class="aArticalListDiv">
				<div class="aArticalList">
					<p @click="getArticalData('')">全部({{num1}})</p>
					<p @click="getArticalData('技术')">技术({{num2}})</p>
					<p @click="getArticalData('游戏')">游戏({{num3}})</p>
					<p @click="getArticalData('电影')">电影({{num4}})</p>
					<p @click="getArticalData('杂谈')">杂谈({{num5}})</p>
				</div>
				<div class="aArticalList">
					<p @click="goCal">进入个人计算器</p>
				</div>
			</div> -->
		</div>
		<div class="pageChanger">
			<el-pagination
				@current-change="handleCurrentChange"
				@size-change="handleSizeChange"
				:current-page="pager.currentPage"
				:page-size ="pager.pageSize"
				:page-sizes="[5,10,20]"
				:total="totalRecords"
				layout="total, sizes, prev, pager, next, jumper"
				>
			</el-pagination>
		</div>
	</div>
</template>

<script>
// @ is an alias to /src
// import HelloWorld from '@/components/HelloWorld.vue'
import api from '../utils/api'
import moment from 'moment'
import { Loading } from 'element-ui'
export default {
	name: 'home',
	data() {
		return {
			articalData: [],
			ori_articalData: [],
			num1: 0,
			num2: 0,
			num3: 0,
			num4: 0,
			num5: 0,
			pager: {
				currentPage: 1,
				pageSize: 5
			},
			totalRecords: 0
		}
	},
	methods: {
		openArtical(id) {
			this.$router.push({name: 'artical', query:{ id: id }})
		},
		getArticalData (label) {
			this.pager.currentPage = 1
			api(`/issues?creator=hkanye&labels=${label}`, 'get').then(
				(res) => {
					this.totalRecords = res.data.length
					for (let i = 0; i < res.data.length; i++) {
						res.data[i].updated_at = moment(res.data[i].updated_at).format('YYYY-MM-DD HH:mm:ss')
					}
					this.ori_articalData = JSON.parse(JSON.stringify(res.data))
					this.articalData = JSON.parse(JSON.stringify(res.data)).slice(0,this.pager.pageSize)
					this.$store.commit('HOME_SAVE_ARTICAL_DATA', res.data)
				}
			)
		},
		goCal () {
			this.$router.push({name: 'cal'})
		},
		handleCurrentChange (val) {
			this.pager.currentPage = val
			this.articalData = JSON.parse(JSON.stringify(this.ori_articalData)).slice((val-1)*this.pager.pageSize,val*this.pager.pageSize)
		},
		handleSizeChange (val) {
			this.pager.currentPage = 1
			this.pager.pageSize = val
			this.articalData = JSON.parse(JSON.stringify(this.ori_articalData)).slice(0,this.pager.pageSize)
		}
	},
	components: {
		// HelloWorld
	},
	mounted() {
		let loadingInstance = Loading.service({fullscreen: true})
		api('/issues?creator=hkanye&labels=', 'get').then(
			(res) => {
				this.$nextTick(() => { // 以服务的方式调用的 Loading 需要异步关闭
					loadingInstance.close();
				});
				for (let i = 0; i < res.data.length; i++) {
					res.data[i].updated_at = moment(res.data[i].updated_at).format('YYYY-MM-DD HH:mm:ss')
				}
				this.articalData = JSON.parse(JSON.stringify(res.data)).slice(0,this.pager.pageSize)
				this.ori_articalData = JSON.parse(JSON.stringify(res.data))
				this.num1 = res.data.length
				this.totalRecords = res.data.length
				for (let i = 0; i < res.data.length; i++) {
					for (let j = 0; j < res.data[i].labels.length; j++) {
						switch (res.data[i].labels[j].name) {
							case '技术':
								this.num2 += 1
								break;
							case '游戏':
								this.num3 += 1
								break;
							case '电影':
								this.num4 += 1
								break;
							case '杂谈':
								this.num5 += 1
								break;
							default:
								break;
						}
					}
				}
				this.$store.commit('HOME_SAVE_ARTICAL_DATA', res.data)
			}
		)
	},
	computed: {
	}
}
</script>

